// countdown-timer.js — extends number-input
// Displays a countdown timer that counts down from a numeric duration (in seconds)

export default function decorate(fieldDiv, fieldJson, container, formId) {
  // fieldDiv is the base number-input HTML structure
  // Extract custom properties if any
  const { initialText = 'Time Remaining', finalText = 'Time\'s Up!' } = fieldJson?.properties || {};

  let model = null;
  let countdownInterval = null;
  let isRunning = false;

  // Find the input and label elements from the base number-input structure
  const input = fieldDiv.querySelector('input[type="number"]');
  const label = fieldDiv.querySelector('.field-label');
  const wrapper = fieldDiv.querySelector('.number-wrapper');

  if (!input) return fieldDiv;

  // Store the original label
  const originalLabel = label?.textContent || 'Countdown Timer';

  // Add countdown button
  const controlsDiv = document.createElement('div');
  controlsDiv.className = 'countdown-timer-controls';

  const startBtn = document.createElement('button');
  startBtn.type = 'button';
  startBtn.className = 'countdown-timer-btn countdown-timer-start';
  startBtn.textContent = 'Start';

  const stopBtn = document.createElement('button');
  stopBtn.type = 'button';
  stopBtn.className = 'countdown-timer-btn countdown-timer-stop';
  stopBtn.textContent = 'Stop';
  stopBtn.disabled = true;

  const resetBtn = document.createElement('button');
  resetBtn.type = 'button';
  resetBtn.className = 'countdown-timer-btn countdown-timer-reset';
  resetBtn.textContent = 'Reset';

  controlsDiv.appendChild(startBtn);
  controlsDiv.appendChild(stopBtn);
  controlsDiv.appendChild(resetBtn);

  // Insert controls after input
  input.parentNode.insertBefore(controlsDiv, input.nextSibling);

  // Countdown logic
  const runCountdown = () => {
    if (isRunning) return;
    isRunning = true;
    startBtn.disabled = true;
    stopBtn.disabled = false;

    countdownInterval = setInterval(() => {
      let currentValue = parseInt(input.value, 10) || 0;
      if (currentValue > 0) {
        currentValue -= 1;
        input.value = currentValue;
        input.dispatchEvent(new Event('change', { bubbles: true }));

        // Update label to show current time
        if (label) {
          label.textContent = `${initialText}: ${currentValue}s`;
        }
      } else {
        // Timer finished
        stopCountdown();
        if (label) {
          label.textContent = finalText;
        }
      }
    }, 1000);
  };

  const stopCountdown = () => {
    if (countdownInterval) {
      clearInterval(countdownInterval);
      countdownInterval = null;
    }
    isRunning = false;
    startBtn.disabled = false;
    stopBtn.disabled = true;
  };

  const resetTimer = () => {
    stopCountdown();
    if (model && model.value) {
      input.value = model.value;
    } else {
      input.value = '';
    }
    input.dispatchEvent(new Event('change', { bubbles: true }));
    if (label) {
      label.textContent = originalLabel;
    }
  };

  // Event listeners for buttons
  startBtn.addEventListener('click', (e) => {
    e.preventDefault();
    runCountdown();
  });

  stopBtn.addEventListener('click', (e) => {
    e.preventDefault();
    stopCountdown();
    if (label) {
      label.textContent = originalLabel;
    }
  });

  resetBtn.addEventListener('click', (e) => {
    e.preventDefault();
    resetTimer();
  });

  // Handle input value changes
  input.addEventListener('change', (e) => {
    const val = parseInt(e.target.value, 10);
    if (val >= 0) {
      if (label && !isRunning) {
        label.textContent = `${initialText}: ${val}s`;
      }
    }
  });

  return fieldDiv;
}

